#!/usr/bin/env python3
# Self-extracting archive: LITIGATIONOS_BLUEPRINT_COREPACK.zip
# Writes OUT_NAME to current directory and verifies CRC32.

import base64, zlib
from pathlib import Path

OUT_NAME = "LITIGATIONOS_BLUEPRINT_COREPACK.zip"
EXPECTED_CRC = 0xe89b7aa5
B64 = ""


def main() -> int:
    out = Path.cwd() / OUT_NAME
    data = base64.b64decode(B64.encode("ascii"))
    got = zlib.crc32(data) & 0xffffffff
    if got != EXPECTED_CRC:
        print(f"CRC32 mismatch: got=0x{got:08x} expected=0x{EXPECTED_CRC:08x}")
        return 2
    out.write_bytes(data)
    print(f"Wrote {out} bytes={len(data)} crc32=0x{got:08x}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
